import React, { useState } from 'react';
import axios from 'axios';

const AudioUpload = () => {
  const [selectedFile, setSelectedFile] = useState(null);
  const [audioId, setAudioId] = useState(null);
  const [uploadedFilePath, setUploadedFilePath] = useState('');
  const [processedFiles, setProcessedFiles] = useState([]);

  const handleFileChange = (event) => {
    setSelectedFile(event.target.files[0]);
  };

  const handleUpload = async () => {
    if (!selectedFile) {
      alert('Please select a file to upload.');
      return;
    }

    const formData = new FormData();
    formData.append('audio', selectedFile);

    try {
      const response = await axios.post('http://localhost:5001/upload', formData);
      setUploadedFilePath(response.data.filePath);
      setAudioId(response.data.audioId);
      alert('File uploaded successfully!');
    } catch (error) {
      console.error('Error uploading file:', error);
      alert('Error uploading file.');
    }
  };

  const handleProcess = async (endpoint, data) => {
    if (!audioId) {
      alert('Please upload a file first.');
      return;
    }

    try {
      const response = await axios.post(`http://localhost:5001/${endpoint}`, { audioId, ...data });
      const newFile = {
        feature: endpoint,
        filePath: response.data.filePath,
      };
      setProcessedFiles((prev) => [...prev, newFile]);
      alert(`${endpoint.replace('-', ' ')} operation successful!`);
    } catch (error) {
      console.error(`Error processing ${endpoint}:`, error);
      alert(`Error processing ${endpoint}.`);
    }
  };

  const downloadFile = (filePath) => {
    const link = document.createElement('a');
    link.href = `http://localhost:5001/${filePath}`;
    link.download = filePath.split('/').pop(); // Get file name from the path
    link.click();
  };

  return (
    <div className="container">
      <h1>Audio Customizer</h1>

      <div className="upload-section">
        <input type="file" onChange={handleFileChange} />
        <button onClick={handleUpload}>Upload Audio</button>
      </div>

      {uploadedFilePath && (
        <div className="uploaded-info">
          <p><strong>Uploaded File:</strong> {uploadedFilePath}</p>
        </div>
      )}

      <div className="process-section">
        <button onClick={() => handleProcess('trim', { start: '30', end: '60' })}>Trim Audio (30s to 60s)</button>
        <button onClick={() => handleProcess('change-speed', { speed: 1.5 })}>Increase Speed (1.5x)</button>
        <button onClick={() => handleProcess('reverse', {})}>Reverse Audio</button>
        <button onClick={() => handleProcess('adjust-volume', { volume: 2.0 })}>Increase Volume (2x)</button>
      </div>

      <div className="processed-files">
        <h2>Processed Files</h2>
        {processedFiles.map((file, index) => (
          <div key={index} className="processed-file">
            <p><strong>{file.feature}:</strong> {file.filePath}</p>
            <button onClick={() => downloadFile(file.filePath)}>Download</button>
          </div>
        ))}
      </div>
    </div>
  );
};

export default AudioUpload;
